package com.example.ecommerce;

import javax.jws.WebService;
import java.util.UUID;

@WebService(endpointInterface = "com.example.ecommerce.OrderProcessingService",
            serviceName = "OrderProcessingService",
            portName = "OrderProcessingPort",
            targetNamespace = "http://ecommerce.example.com/")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    @Override
    public OrderResponse processOrder(OrderRequest request) {
        OrderResponse response = new OrderResponse();
        try {
            if (request == null || request.getItems() == null || request.getItems().isEmpty()) {
                response.setOrderId(null);
                response.setTotalAmount(0.0);
                response.setStatus("FAILED");
                response.setMessage("Order request is empty or invalid. No items provided.");
                return response;
            }

            double totalAmount = 0.0;
            for (OrderItem item : request.getItems()) {
                if (item.getPrice() <= 0 || item.getQuantity() <= 0) {
                    throw new IllegalArgumentException("Item price and quantity must be positive values.");
                }
                totalAmount += item.getPrice() * item.getQuantity();
            }

            String orderId = UUID.randomUUID().toString(); // Generate a unique order ID
            // Simulate saving order to a database or further processing
            System.out.println("Processing order: " + orderId + " with total amount: " + totalAmount);
            request.getItems().forEach(item ->
                System.out.println("  Item: Price=" + item.getPrice() + ", Quantity=" + item.getQuantity())
            );

            response.setOrderId(orderId);
            response.setTotalAmount(totalAmount);
            response.setStatus("PROCESSED");
            response.setMessage("Order successfully processed.");

        } catch (IllegalArgumentException e) {
            response.setOrderId(null);
            response.setTotalAmount(0.0);
            response.setStatus("FAILED");
            response.setMessage("Validation error: " + e.getMessage());
        } catch (Exception e) {
            response.setOrderId(null);
            response.setTotalAmount(0.0);
            response.setStatus("FAILED");
            response.setMessage("An unexpected error occurred: " + e.getMessage());
            e.printStackTrace(); // Log the exception for debugging
        }
        return response;
    }
}
